/* selectBillHistoryDtlList */ SELECT bid.bill_dtl_id, bid.calculation_company_id, com.company_nm, com.email , com.fax_no, bid.bill_id, bid.bill_dtl_dgre, bid.tot_amount , bid.tot_count, bid.communication_fee, bid.communication_fee_vat , bid.untpc, bid.untpc_vat, bid.weight_untpc, bid.weight_untpc_vat , bid.reg_id, bid.reg_dt, bid.chg_id, bid.chg_dt, bid.del_yn , CONCAT(TO_CHAR(mh.send_dt, 'YYYY-MM-DD HH24:MI:SS'), ' ', co.code_nm) AS send_status FROM bill_dtl bid INNER JOIN company com ON com.company_id = bid.calculation_company_id INNER JOIN ( SELECT bill_id, calculation_company_id, MAX(bill_dtl_dgre) AS max_dgre FROM bill_dtl WHERE del_yn = 'N' GROUP BY bill_id, calculation_company_id ) maxdgre ON bid.bill_id = maxdgre.bill_id AND bid.calculation_company_id = maxdgre.calculation_company_id AND bid.bill_dtl_dgre = maxdgre.max_dgre LEFT JOIN ( SELECT mh1.bill_id, mh1.bill_dtl_id, mh1.send_dt, mh1.mail_status_cd FROM mail_history mh1 INNER JOIN ( SELECT bill_id, bill_dtl_id, MAX(send_dt) AS latest_send_dt FROM mail_history WHERE del_yn = 'N' GROUP BY bill_id, bill_dtl_id ) mh2 ON mh1.bill_id = mh2.bill_id AND mh1.bill_dtl_id = mh2.bill_dtl_id AND mh1.send_dt = mh2.latest_send_dt WHERE mh1.del_yn = 'N' ) mh ON mh.bill_id = bid.bill_id AND mh.bill_dtl_id = bid.bill_dtl_id LEFT JOIN code co ON co.code_val = mh.mail_status_cd AND co.type = 'MAIL_STATUS' AND co.del_yn = 'N' WHERE bid.del_yn = 'N'
AND bid.bill_id = #{billId}
AND bid.bill_dtl_id = #{billDtlId}
AND UPPER(com.company_nm) like UPPER(CONCAT('%',#{companyNm},'%'))
ORDER BY com.company_nm DESC

